int coinChangeBruteForce(vector<int>& coins, int amount) {
    if (amount == 0) {
        return 0;
    }

    int minimumCoinsNeeded = numeric_limits<int>::max();

    function<void(int, int, int)> solve = 
        [&](int remainingAmount, int currentCoinIndex, int currentCoinCount) {
        if (remainingAmount == 0) {
            minimumCoinsNeeded = min(minimumCoinsNeeded, currentCoinCount);
            return;
        }

        if (remainingAmount < 0 || currentCoinIndex >= coins.size()) {
            return;
        }

        // Try using zero of the current coin
        solve(remainingAmount, currentCoinIndex + 1, currentCoinCount);

        // Explore using multiple instances of current coin
        int numberOfCurrentCoins = remainingAmount / coins[currentCoinIndex];

        for (int count = 1; count <= numberOfCurrentCoins; ++count) {
            int nextRemainingAmount = remainingAmount - count * coins[currentCoinIndex];

            //  Recursively explore possibilities
            solve(nextRemainingAmount, currentCoinIndex + 1, currentCoinCount + count);
        }
    };

    // Start recursion at first coin
    solve(amount, 0, 0);

    // If no solution found, return -1
    return (minimumCoinsNeeded == numeric_limits<int>::max()) ? -1 : minimumCoinsNeeded;
}

