fn coin_change_brute_force(coins: Vec<i32>, amount: i32) -> i32 {
    let mut minimum_number_of_coins: i32 = -1;

    fn find_minimum_coins(remaining_amount: i32, current_combination: Vec<i32>,
        coins: &Vec<i32>,
        minimum_number_of_coins: &mut i32) {

        if remaining_amount == 0 {
            // Found a valid combination. Check if it's the best so far.

            let number_of_coins_in_combination = current_combination.len() as i32;
            if *minimum_number_of_coins == -1 || number_of_coins_in_combination < *minimum_number_of_coins {
                *minimum_number_of_coins = number_of_coins_in_combination;
            }
            return;
        }

        if remaining_amount < 0 {
            // This combination is invalid. It exceeds the amount.
            return;
        }

        for coin_index in 0..coins.len() {
            let coin = coins[coin_index];

            // Explore using this coin by adding it to the current combination
            let mut next_combination = current_combination.clone();
            next_combination.push(coin);
            find_minimum_coins(remaining_amount - coin, next_combination, coins, minimum_number_of_coins);
        }
    }

    // Start recursive search with an empty combination
    find_minimum_coins(amount, Vec::new(), &coins, &mut minimum_number_of_coins);

    minimum_number_of_coins
}

