                currentCoinCount + numberOfCoins,
                coinIndex + 1)
        }
    }

    //Sort the coins for optimization.
    coins.sortDescending()

    // Initiate the process with the largest coin
    findMinimumCoins(amount, 0, 0)

    //If no solution was found.
    if (minimumNumberOfCoins == Integer.MAX_VALUE) {
