  dpTable[0] = 0;

  // Iterate through each possible amount.
  for (let currentAmount = 1; currentAmount <= amount; currentAmount++) {
    for (const coin of coins) {
      // Only process if coin is less than current amount.
      if (coin <= currentAmount) {

        // Calculate the subproblem result
        dpTable[currentAmount] = Math.min(
          dpTable[currentAmount],
          dpTable[currentAmount - coin] + 1
        );
      }
    }
  }

  // If no solution was found return -1.
  return dpTable[amount] > amount ? -1 : dpTable[amount];
